// // This module decrements a 4-bit binary counter on every positive edge of the clock and resets to zero when a reset signal is low.
module up_counter (
    input clk,
    input reset,
    output reg [3:0] count);always @(posedge clk or posedge reset)
    if (reset)
        count <= 4'b0000;
    else
        count <= count + 1;

endmodule
